#include <iostream>

class Volume {
private:
    int m_level{ 0 };

public:
    int getLevel() const { return m_level; }

    void setLevel(int v) {
        if (v < 0)   v = 0;
        if (v > 100) v = 100;
        m_level = v;
    }
};

int main() {
    int a, b;
    std::cin >> a >> b;

    Volume vol;
    vol.setLevel(a);
    std::cout << vol.getLevel() << '\n';
    vol.setLevel(b);
    std::cout << vol.getLevel() << '\n';

    return 0;
}

