solution_code:
#include <iostream>

class Odometer {
private:
    int m_miles{ 0 };

public:
    void addMiles(int m) {
        if (m > 0)
            m_miles += m;
    }

    int getMiles() const { return m_miles; }
};

int main() {
    int a, b;
    std::cin >> a >> b;

    Odometer odo;
    odo.addMiles(a);
    std::cout << "Miles: " << odo.getMiles() << '\n';
    odo.addMiles(b);
    std::cout << "Miles: " << odo.getMiles() << '\n';

    return 0;
}
